(window.webpackJsonp=window.webpackJsonp||[]).push([[379],{1006:function(n,r){n.exports='\x3c!-- \r\ntitle: 08-Nginx+Tomcat\r\nsort: \r\n--\x3e \r\n\r\n> 配置文件列表\r\n>\r\n> `/etc/nginx/nginx.conf`\r\n>\r\n> `/etc/nginx/sites-enabled/default`\r\n>\r\n> `/opt/lib/tomcat9/webapps/`\r\n\r\n## Nginx配置文件\r\n\r\n```nginx\r\n# /etc/nginx/sites-enable/default\r\n\r\nserver {\r\n\tlisten 80;\r\n    server_name localhost;\r\n\r\n\tlocation / {\r\n\t\troot /var/www/html;\r\n\t\tindex index.html index.htm index.nginx-debian.html;\r\n\t}\r\n}\r\n\r\ninclude\t<someconfig>\r\n```\r\n\r\n### 反向代理\r\n\r\n```nginx\r\nlocation /test {\r\n\t# 反向代理\r\n\tproxy_pass http://group1/;\r\n}\r\n```\r\n\r\n### 负载均衡\r\n\r\n```nginx\r\n# 负载均衡 权重\r\nupstream group1 {\r\n   \tserver 192.168.0.1:80 weight=2;\r\n    server 192.168.0.1:8080 backup;\r\n}\r\n\r\nserver{\r\n    location /test/ {\r\n        # 随机重定向到两个网页\r\n\t\tproxy_pass http://group1/;\r\n  }\r\n}\r\n```\r\n\r\n## Tomcat\r\n\r\n```bash\r\ncd /var/lib/tomcat9/webapps/\r\n```\r\n\r\n## Git\r\n\r\n```\r\ngit clone\r\ngit push\r\ngit pull\r\ngit status\r\ngit branch -v\r\ngit add .\r\ngit commit -a -m "Message"\r\ngit checkout .\r\ngit checkuot -b new_branch\r\ngit merge\r\n```\r\n\r\n'}}]);